using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Build chat client with automatic tool invocation ───────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ── Register tools ─────────────────────────────────────────────────
var noteStore = new NoteStore();
var chatOptions = new ChatOptions
{
    Tools = new List<AITool>
    {
        AIFunctionFactory.Create(WebSearchTool.SearchAsync),
        AIFunctionFactory.Create(noteStore.SaveNote),
        AIFunctionFactory.Create(noteStore.GetNotes),
    }
};

// ── Get topic ──────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// ── Run the agent loop ─────────────────────────────────────────────
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. Your workflow:
        1. Search the web for the topic from at least 3 different angles or sub-queries.
        2. After each search, save the most important findings as notes (use descriptive labels).
        3. Once you have gathered enough material, retrieve your notes.
        4. Write a well-structured summary with an introduction, key findings, and takeaways.

        Be factual, cite specifics when possible, and be concise but comprehensive.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}")
};

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n─── Research Summary ───────────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n────────────────────────────────────────────────\n");

// ════════════════════════════════════════════════════════════════════
// Tools
// ════════════════════════════════════════════════════════════════════

/// <summary>Web search tool backed by the DuckDuckGo Instant Answer API.</summary>
public static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information. Returns relevant snippets for a query.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        try
        {
            var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}"
                    + "&format=json&no_html=1&skip_disambig=1";

            Http.DefaultRequestHeaders.UserAgent.Clear();
            Http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

            var json = await Http.GetStringAsync(url);
            var doc  = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var snippets = new List<string>();

            // Abstract / summary
            var abs = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abs))
                snippets.Add($"[Summary] {abs}");

            var src = root.GetProperty("AbstractSource").GetString();
            var absUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(src))
                snippets.Add($"[Source] {src} — {absUrl}");

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var t in topics.EnumerateArray().Take(8))
                {
                    if (t.TryGetProperty("Text", out var text))
                    {
                        var snippet = text.GetString();
                        if (!string.IsNullOrWhiteSpace(snippet))
                            snippets.Add(snippet);
                    }
                    // Handle sub-topics (groups)
                    else if (t.TryGetProperty("Topics", out var subTopics))
                    {
                        foreach (var st in subTopics.EnumerateArray().Take(3))
                        {
                            if (st.TryGetProperty("Text", out var stText))
                            {
                                var snippet = stText.GetString();
                                if (!string.IsNullOrWhiteSpace(snippet))
                                    snippets.Add(snippet);
                            }
                        }
                    }
                }
            }

            var result = snippets.Count > 0
                ? string.Join("\n", snippets)
                : "No results found. Try rephrasing the query.";

            Console.WriteLine($"  ✅ {snippets.Count} snippet(s) found\n");
            return result;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ❌ Search failed: {ex.Message}\n");
            return $"Search error: {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Simple in-memory note store for the research agent.</summary>
public sealed class NoteStore
{
    private readonly List<(string Label, string Content)> _notes = [];

    [Description("Save a research note. Use this to record important findings during research.")]
    public string SaveNote(
        [Description("A short label or category for the note")] string label,
        [Description("The note content to save")] string content)
    {
        _notes.Add((label, content));
        Console.WriteLine($"  📝 Note saved: [{label}]");
        return $"Note #{_notes.Count} saved under '{label}'.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)\n");
        return string.Join("\n",
            _notes.Select((n, i) => $"{i + 1}. [{n.Label}] {n.Content}"));
    }
}

